#!/usr/bin/env python3
"""One-shot save of slug pair batch from hardcoded fetch results."""
import json
import subprocess
import sys
from pathlib import Path

ROOT = Path(__file__).resolve().parent

PAIRS = [
    {"megaeth": "", "cartesi": ""},
]

def save(data):
    proc = subprocess.run(
        [sys.executable, str(ROOT / "save_b64_map_stdin.py")],
        input=json.dumps(data),
        text=True,
        capture_output=True,
    )
    print(proc.stdout.strip())

if __name__ == "__main__":
    merged = {}
    for p in PAIRS:
        merged.update(p)
    save(merged)
